import{_ as e}from"./_plugin-vue_export-helper-DlAUqK2U.js";import{a,o as t,s as o}from"./index-C3q21NtK.js";const l={},r={class:"min-h-screen bg-linear-to-br from-blue-50 to-indigo-100 p-6"};function i(n,s){return t(),a("div",r,[...s[0]||(s[0]=[o('<div class="max-w-7xl mx-auto space-y-10"><section class="rounded-2xl bg-white shadow-lg p-8 md:p-12 flex flex-col gap-6"><div class="space-y-3 max-w-3xl"><p class="text-sm uppercase tracking-wide text-blue-600 font-semibold">About</p><h1 class="text-3xl md:text-4xl font-bold text-gray-900 leading-tight">What is Contrail?</h1><p class="text-gray-700 text-base leading-relaxed"> Contrail is a platform for building personal learning paths. It helps you turn scattered resources—found across YouTube, blogs, and course platforms—into a clear, actionable path you can actually finish. Instead of collecting links and losing momentum, you get structure, progress, and feedback in one place. </p></div><div class="grid gap-4 sm:grid-cols-2 lg:grid-cols-3"><div class="rounded-xl bg-blue-50/50 shadow-sm p-4"><h3 class="font-semibold text-gray-900">Resources</h3><p class="text-sm text-gray-700 mt-1">Import videos, articles, documents, and links—then manage them in one library instead of browser bookmarks.</p></div><div class="rounded-xl bg-purple-50/40 shadow-sm p-4"><h3 class="font-semibold text-gray-900">Learning Paths</h3><p class="text-sm text-gray-700 mt-1">Drag resources into a path, reorder steps, and shape a learning rhythm that fits your goal and schedule.</p></div><div class="rounded-xl bg-green-50/40 shadow-sm p-4"><h3 class="font-semibold text-gray-900">Progress</h3><p class="text-sm text-gray-700 mt-1">Track progress per resource and see how much of a path you’ve completed—so learning stays continuous, not fragmented.</p></div></div></section><section class="grid gap-6 md:grid-cols-2"><div class="rounded-2xl bg-white shadow-lg p-6 space-y-3"><h2 class="text-xl font-semibold text-gray-900">Why Contrail</h2><ul class="space-y-2 text-gray-700 text-sm leading-relaxed list-disc list-inside"><li>Your learning resources are scattered across platforms and hard to organize systematically.</li><li>You save a lot, but you don’t know where to start—or where you stopped.</li><li>Learning happens in small fragments, but you lack a single framework to measure progress and outcomes.</li><li>Contrail’s goal is to turn fragmented learning into structured, repeatable progress.</li></ul></div><div class="rounded-2xl bg-white shadow-lg p-6 space-y-3"><h2 class="text-xl font-semibold text-gray-900">Core Features</h2><ul class="space-y-2 text-gray-700 text-sm leading-relaxed list-disc list-inside"><li><span class="font-semibold">Resource</span>: discover public resources and keep your own private library.</li><li><span class="font-semibold">Learning Path</span>: build a path by adding resources, reordering steps, and categorizing.</li><li><span class="font-semibold">Progress</span>: record learning progress per step and see overall completion at a glance.</li><li><span class="font-semibold">Personal Pool</span>: save quick ideas (links, images, notes) and turn them into resources later.</li><li><span class="font-semibold">Public &amp; Private</span>: choose what you share and what stays personal.</li></ul></div></section></div>',1)])])}const p=e(l,[["render",i]]);export{p as default};
